import{o as p,c as e,D as m}from"./framework.2deede19.js";const t='{"title":"Глава 8","description":"","frontmatter":{"title":"Глава 8","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-09-20T00:00:00.000Z"},"headers":[{"level":2,"title":"Восьмая глава","slug":"восьмая-гnава"}],"relativePath":"texts/malini-vijayottara/8.md","lastUpdated":1624912858209}',a={},r=m('<h2 id="восьмая-гnава"><a class="header-anchor" href="#восьмая-гnава" aria-hidden="true">#</a> Восьмая глава</h2><p>(Шива сказал):</p><p>Теперь поведаю о жертвоприношении, дающем (исполнение) всех желаний, благодаря познанию которого (садхака) станет равным йогини ..1.</p><p>Вначале следует подготовить место для жертвоприношения в чистой местности, радующей ум, вместе с круглой огненной ямой;.2.</p><p>Для почитания, разделенное на 25 равных частей с центральной частью, окруженной со всех сторон четырехугольной оградой, украшенной парвауштхеной (т.е. передней частью агникунды) ..3.</p><p>Затем совершается омовение. Побеждая двойственность омовением элементами, знающий мантру пусть совершает его шесть видов, начиная с омовения в пепле. Омываясь от грязи при омовении пеплом, заговоренным семь раз великой астра (биджей) следует натереть (им) тело в обратном порядке (<em>с головы до ног</em>). Затем вначале следует покрыть голову 5 членными видьями. (Затем) совершается омовение (водой) с шестичленной мула мантрой ..4-6.</p><p>Затем в прекрасной одежде или без одежды, следует очистить руки и стопы. Совершив ачаману, следует выполнить марджану (кропление), с видьей и множеством варн ..7.</p><p>Выполнив ньясу, затем (совершается) общая агхамаршана, (затем) упастхана, (затем) следует произнести на четках односложную (мантру) ..8.</p><p>При омовении водой и глиной, заговоренной 7 раз астра (биджей), жертвуя, как и ранее (собственное) тело, следует совершить омовение для (очищения) от загрязнения ..8-9.</p><p>Как и ранее, это омовение совершается с водой, как подобает. Одновременно омываясь и произнося трижды видья (мантру) пусть знающий мантру выльет себе на голову воду, с омывающей мантрой. Пусть совершит так же омовение пространством, навозом, ветром. Произнося великую астра (биджу), пусть пройдет, созерцая 7 шагов. Пусть снова пройдет, размышляя над парапара (видьей) ..10-12.</p><p>Этот (путь) считается равным году тапаса, божественной йоги. Пусть произносящий мантру созерцает (уровень) пара, как поток амриты ..13.</p><p>Поднимая огонь от основания больших пальцев (стоп) пусть он сожжет (свое тело) астра (биджей). Затем следует омыть свое тело амритой пара ..14.</p><p>Поднеся мантру солнцу и другим (богам), памятуя астра (биджу), следует отправится в место жертвоприношения, очищенное астра (биджей). Пусть он войдет (туда) чистым и возвышенным ..15.</p><p>Почтив там для устранения препятствий, покровителей врат, произнося астра (биджу) следует поместить (туда) цветы, созерцая огонь. Следует войти в место жертвоприношения, подобно огню и держа огонь ..16.</p><p>Следует выполнить ограждение десяти направлений астра (биджей). Войдя с востока или с лунного направления (<em>с севера</em>) следует приступить (к выполнению) ньясы с астра мантрой и огнем вечности (каланала). Следует созерцать, начиная с больших пальцев ног, превращающееся в пепел тело облаченное в броню ветра. Следует созерцать себя единым с Шивой и бинду. Затем следует соединиться с Его Шакти. «Она есть Я» (СА’ХАМ) есть непобедимая мантра ..17-20.</p><p>Затем следует добавить к этой мантре, образу Видьи, о Шанкари, «шаг палки», «великую прану», «выросшую палку», с «пупом» и «ягодицами». После них - «левую грудь», после нее - «горло», «левую вершину», украшенную «левой мудрой», бинду, полумесяц, небо украшенное надой, шакти и бинду. Это лучшая пинда (мантра), о Деви именуется девятисложной.(<em>по всей видимости имеется в виду наватма мантра</em>: Х Р КШ М Л В Й Н УМ) .21-23.</p><p>Творящая все совершенства, произносимая втайне. Ниже этой трещащей мантры следует разместить по порядку шаданга (Ньясу), начиная с сердца с шестью долгими гласными. В начале следует разместить «уста», с биджами: КША, РА, ВА, ЛА, украшенными сияющими бинду. Начиная с уст и (далее по порядку). Затем следует разместить в каждой части тела начиная со лба: .23-26.</p><p>(Гласная) А (размещается) на лбу, на рот следует поместить вторую (гласную АА). На глаза - И и ИИ. На оба уха У и УУ. На ноздри - Р и РР, на щеки - Л и ЛР. На верхние и нижние зубы (помещаются) Э и АЙ. Слоги О и АУ - на губы ..24-27.</p><p>На макушке следует разместить (анусвару) АМ, висаргу - на языке, на правую дельту, плечо, предплечье, кисть и ноготь большего пальца следует поместить КА- варгу. Слева (на левую руку следует поместить) по порядку (ЧА Варгу) начиная с ЧА. Две Варги начинающихся с ТА ТА следует разместить начиная с ягодиц ..29-30.</p><p>На стопы, на оба бока, на спину, на живот и сердце по порядку, на линию кожи, крови, мяса, следует поместить ЙА- варгу ..31.</p><p>(Полугласные), начиная с ША помещаются в пятерку: кости, жир, семя, прана, и отверстия (тела). Разместив части тела мурти, пусть мудрый призовет Шиву ..32.</p><p>Над «праной» следует поместить «пуп», сверху него - «правый большой палец», «левое ухо» - это постигаемый, дающий все совершенства Шива. Это - Великая Сущность Бхайравы, Великого Духа. При помощи этой (мантры) выполняются действия над частями тела как (было описано) ранее в соответствии с разделением гласных ..33-34.</p><p>Мурти ньяса (<em>ньяса наватмамантры вместе с анга ньясой</em>), сришти ньяса (<em>матрика ньяса</em>)<em>,</em> три таттва ньяса (<em>ньяса Шива таттвы, Видьи, и Атмы</em>) ньяса восьми частей мурти, Шива вместе с ангами - именуется шестичастная Шива Ньяса ..35.</p><p>После нее следует выполнить шакта ньясу. Слушай, как (это следует сделать). Следует поместить в Мурти парапара (мантру) и ее «уста», (затем) малини. Затем следует (разместить) Ньясу начиная с пара в трех (местах): макушке, сердце и стопах. Восьмерку видий, начиная с Агхори и видьянгу как и ранее (следует разместить) на макушку, рот горло, сердце, пупок, «тайное место», бедра и стопы. Затем следует призвать Шакти, почитаемую всеми йогинами ..36-38.</p><p>Джива пребывающая посреди ограждения, сияющая, подобно огню уничтожения, Пресветлая, с украшенной левой ногой, с головой увенчанной бинду ..39.</p><p>Она связана с правым коленом, вмещает все сонмы матерей. Ею (они) все удовлетворяются, (она) дает желанный плод ..40.</p><p>Это именуется высшей сущностью Матерей, поэтому, их (мантры) произносящий мантру желающий совершенства должен произносить ..41.</p><p>Вечно пребывает единство Рудры и Шакти. Из него происходит Высшая Шакти, именуемая (пребывающей) в отдельности ..42.</p><p>Поскольку все совершенства в основе (пребывают) в ней, ею они творятся. Следует разместить ее части тела вместе с гласными, как ранее (в шаданга ньясе) ..43.</p><p>Мурти с устами, Шакти, видья- третья, восьмерка, начиная с Агхори, и видьянга (ньяса)- пятая. Вместе с частями тела это именуется Ньясой Высшей Шакти шести видов. За этой парой (ньяс) следует ньяса, дающая все совершенства ..44-45.</p><p>Правило левого ткачества (<em>т.е. тантры левой руки</em>) должно выполнятся через различение варны и мантры желающими плода освобождения или, отдельно, желающими (другого) плода ..46.</p><p>Для каждого вида (мантр), разделяемых на Шамбху, Шакти и Ану (мантры), выполняется своя ньяса пяти видов ..47.</p><p>Это - внешняя (Ньяса) включает также анга (ньясу). Шестая (<em>вьяпака ньяса</em>) (выполняется) повсюду (<em>т.е. по всему телу</em>). Так происходит очищение (тела) ..48.</p><p>Не прерывая своего пребывания в размышлении о сущем и не- сущем, мудрым следует подготовить подобающие компоненты жертвоприношения ..49.</p><p>Затем следует установить сосуд аргхьи, представляющий сущее и не-сущее. Затем следует зажигание огня и омовение водой Шакти для очищения ..50.</p><p>Либо очищение выполняется другими элементами. Таким путем следует действовать знающему ..51.</p><p>Ни какой предмет не следует считать нечистым. Благодаря этому, все (становится) чистым, даже нечистое (станет) чистым ..52.</p><p>Водой наполнив сосуд и выполнив анга ньясу и амритакарну, этой водой следует очистить все компоненты ..53.</p><p>Почтив Атман, следует выполнить внутреннее (поклонение). Поведаю теперь Тебе (дальнейшее), о Почитаемая всеми сонмами йогов!.54.</p><p>Вначале (следует созерцать) на четыре ангулы ниже пупка поддерживающие (адхара) шакти: Дхару, Суроду, Поту и Канду, четвертую ..55.</p><p>(Точка на) четыре ангулы (ниже пупка) является истоком трезубца. В его рукояти следует представить Налу и Ананту ..56.</p><p>Выше Ламбики (<em>индра-йони чакра, между носом и горлом</em>), вверху трезубца - «яблоко». Им пробивается, о Махадева, великий океан сети оков ..57.</p><p>Без него человек не достигает единства с Шивой (Шива йоги). (Вокруг него), по промежуточным направлениям, начиная с юго-восточного, произносящий мантру должен созерцать Дхарму, Джнану, Вайрагью и Айшварью - четвертую. По четырем (основным) направлениям, начиная с востока, он должен памятовать четырёх слонов- земледержцев ..58-59.</p><p>Выше «яблока», ниже трезубца созерцается четверка. Ее именуют видья таттвой, вместе с тремя ее покровами ..60.</p><p>Эту таттву следует созерцать между КА- КХА (<em>т.е. треугольником А-КА-КХА</em>) и Ламбикой. Пусть мудрый созерцает могущественную КА и КХА таттву в форме лотоса;.61.</p><p>Наделенного венчиком и тычинками, вместе с раскрывающимся белым семенем. Начиная с восточного лепестка (в нем) следует разместить девятку, начиная с Вамы ..62.</p><p>Вама, Джьештха, Раудри, Кали, Калавикарани, Сарвабхутадамани и Манонмани в центре- следует разместить по ходу солнца ..63-64.</p><p>В обратном порядке следует разместить другую девятку, начиная с Вибху: Вибху, Джнани, Крия, Чештва, Вагиши, Джвалини, Вама, Джьештха, Раудри, все сияющие как огонь конца времен. Сначала размещаются шакты: Брахма, Вишну и Хара ..65-66.</p><p>В середине, венчике в лепестках мандал пребывают эти владыки. Следует созерцать их, обозначаемых Речью, Солнцем, Луной и огнем ..67.</p><p>Ишвара, Махапрета, Сияющий, вместе с умом, обладающий телом (сияющим) как десять миллионов огней вечности - место пребывания их всех ..68.</p><p>Из его пупка вырастает Шакти. Ее следует созерцать как три зубца трезубца. Трехконечный КА-КХА упирается в двадашанту ..69.</p><p>Следует созерцать в его зубцах три лотоса Шакти. Белый, всеподдерживающий- такова асана Пара (шакти) ..70.</p><p>На ней следует созерцать образ, именуемый Видьей, в ней -Атман, в него (выполняется) пурва ньяса, наполненная Шивой ..71.</p><p>Затем в середину между двумя (зубцами), северным и южным (помещается) высшая Шакти, в форме Парапара, великосильная, красного цвета ..72.</p><p>Следует созерцать ее как Грозную, принимающую форму Воли, неустрашимую. В левом зубце- Апара, Красно- черная, устрашающая ..73.</p><p>Деви, принимающая форму Воли, Почитаемая, Уничтожительница бед, Высшая (Пара) Проникающая Деви, Сияющая как миллиард солнц ..74.</p><p>В шакти шести видов следует созерцать эти образы. Затем следует разместить части тела пятерки видий, начиная с юго-востока ..75.</p><p>В направлениях Агни, Ишы, Ракши, Ваю, и Юга, по порядку, следует созерцать как подобает, части тела Шакти, и части тела Шивы ..76.</p><p>(Так же и) По направляениям, начиная с Шакры с астра мантрой. В середину (размещается) «глаз». Следует созерцать (по этим направлениям)восьмерку, начиная с Агхоры, вместе с восьмеркой, начиная с Агхори ..77.</p><p>Снаружи равномерно, по порядку (размещаются) локапалы. Созерцая их всех вместе с их собственными мантрами, следует затем приступить к джапе ..78.</p><p>(Созерцая, как они) становятся растворенными в изначальной форме, каждого следует созерцать десятикратно. Созерцая сияющее пламя огня, следует в конце произнести СВАХА ..79.</p><p>Пусть произносящий мантру сделает так один раз, (созерцая) одного за другим, ради успеха в обряде хомы. Это именуется ментальным жертвоприношением самудаяка ..80.</p><p>Так (выполняется) установка тришулы с одной рукоятью, и тремя Шакти. Так (испрашивается) повеление у трезубца, о Прекрасноликая!.81.</p><p>Приняв кхечари мудру, не следует отрываться от поверхности земли. Это именуется шамбхава (дхьяна), после восьмой (чакры) она называется шакта ..82.</p><p>После четвертой она известна как анава. Такова тришула. Отдельно от обряда жертвоприношения следует созерцать шакти чакру ..83.</p><p>Благодаря этому, приняв кхечари (мудру) йогин сможет оторваться от поверхности земли. Затем, произнося мантру с махастрой 10 раз, следует разбросать по всем сторонам света деньги, созерцая (как они сгорают) словно от пламени огня. Созерцая дом (жертвоприношения) лишенным препятствий, следует повернуться на северо-восток (удалив их) ..84-85.</p><p>Затем пусть мудрый сделает паньча гавью из пяти компонентов. (Это): коровья моча, навоз, молоко, простокваша и масло ..86.</p><p>Следует произнести мантру шаданга (ньясы) сверху и вокруг, (используя) воду и траву куша. Выполнив амрита (карана) мудру над компонентами (жертвоприношения), следует созецать его сущность ..87.</p><p>Пусть затем выполнит жертвоприношение васту (пуруше), произнося малини ..88.</p><p>Сложив руки в анджали (мудру) и произнося (слоги), начиная с ПХА (ХА), созерцая адхву закнчивающующуся на Шакти и после слога НА следует бросить (подношение) ..89.</p><p>Следует почитать Ганешу, поднося благовония, курения и прочее. На асану помещаются сверху (подношения) с шестью прозношениями пранавы ..90.</p><p>(Произнося слог) ГАМ, следует жертвовать Вигнеше благовония, курения и прочее. Его Анга (Ньяса) выполняется с шестью долгими гласными ..91.</p><p>Произнося тринетру, и созерцая Гаджу, в образе Вамы. Отпуская (следует произнести): Да будет совершенно. Так следует почитать великое оружие ..92.</p><p>Следует разместить Ананту, Дхарму, Джнану и Вайрагью и Айшварью в венчике. Такова асана, (имеющая) шесть опор ..93.</p><p>Выше нее следует разместить, созерцая, (Шиву), держащего меч и цветок кетаки, устрашающего, с огромными клыками, с лицом украшенным сросшимися бровями, наделенного шестью его частями, окруженного по сторонам света Матерями, освященного собственными шестью частями Ревы, и слогом ПХАТ ..95.</p><p>Созерцая такую форму, следует затем почитать восьмерку Матерей. В восточном лепестке, следует созерцать Индрани вместе с ваджрой ..96.</p><p>(В юго-восточном лепестке следует созерцать) Агнеи, держащую в руках копье, (в южном лепестке) Ями держащую в руках палку. Следует также созерцать Найрити, Варуни, Ваяви, вместе с их (оружием), мечем, силком и флагом, о Возлюбленная! А также Каубери, держащую в руках молот и Ишани вместе с трезубцем ..97-98.</p><p>Почтив, их благовониями, цветами и прочим следует совершить свободно хому. Вначале следует подготовить калашу, заговоренную мантрами более тысячи раз ..99.</p><p>Затем следует выполнить хому тысячу раз, (затем), выполнив джапу, следует произвести висарджану. Выполнив полностью (джапу) сто восемь раз, следует приступить к жертвоприношению ..100.</p><p>В начале устанавливается сосуд сделанный из золота и прочего, со всеми мантрами целебными травами внутри, наполненный ароматной водой ..101.</p><p>С ветками манго (размещенными) в горлышке, с белой нитью перевязанной по горлышку, отмеченный тилакой для устранения злых духов, завернутый в два куска белой ткани ..102.</p><p>Почитаемый муламантрой, повторенной сто восемь раз. Затем он почитается с астра мантрой Вардхани; .103.</p><p>Поднесением старательно асане пригоршней (подношений) как было описано. Затем следует почтить Индру и прочих (богов, расположенных) по сторонам света с произнесением гласных ..104.</p><p>Разделив землю, следует поднести (подношения) Вардхани. Обведя калашу, следует произнести такую мантру Владыки мира (Индры):.105.</p><p>О, о, Шакра, в направлении твоей обители, ради устранения препятствий да будет тщательно совершен обряд по Воле Шивы!.106.</p><p>Перенеся туда прежде сидение, следует поместить сосуд, представляющий мурти. С правой (южной) стороны от него следует разместить Вардхани ..107.</p><p>По окончании почитания его в образе Атмана, следует разместить (ее) в сосуде. Благовониями, цветами и прочим следует затем почитать в нем Вардхани ..108.</p><p>Сделав старательно благовониями мандалу, (представляющую) область Брахмана (священное пространство) следует почитать Шестерку, Тройку или единицу ..109.</p><p>(Затем следует) расчерчивание жертвенной ямы, ее разделение, умащение, (затем черчение) перекрестка, ограждение, установка ваджры ..110.</p><p>(Затем) производится выстилание (огненной ямы) травой куша и раскладка дров. Все это выполняется с астра (мантрой), затем следует добавить видья (мантру), и ОМ и ХРИМ ..111.</p><p>Затем, совершая почитание, добавляется два (слова) ШИВА и ОМ. В сосуд или в стрелу следует призвать Джатаведаса (Огонь) ..112.</p><p>Созерцая Шиву, как семя, следует поместить его в лоно Видьи. Затем, (выполняя) пять ахути следует выполнить хому Видье, вместе с ее частями тела ..113.</p><p>Затем (выполняется) обряд рождения и прочего, затем выполняются все необходимые обряды. Созерцая параапара (видью) следует поднести пурнахути ..114.</p><p>Следует почтить мать огня и его отца, а затем отпустить. Используя возлияние масла, следует затем разжечь огонь ..115.</p><p>Вбирая с дыханием огонь мысленно через левую (ноздрю) и задержав его в сердце, следует (затем) выпустить его через правую (ноздрю) ..116.</p><p>Затем, как и ранее, следует поднести пурна (ахути). Таково низшее правило огня Шивы. Созерцая Его, как форму Шивы и Свой Атман, пусть произносящий мантру выполнит по порядку внутренне (поклонение). Выполнив внутреннее поклонение, следует приступить к хоме. Выполнив сто раз с мула (мантрой) тарпану с ее частями и шаданга (ньясой), оставшейся десятой частью от мантры (выполняется) тарпана. Затем следует привести ученика, чистого телом и сытого ..118-119.</p><p>Поклонившись, согласно порядку, Владыке богов, пребывающему на перекрестке, следует</p><p>поднести панчагавью, тепленное масло и полоскание для зубов ..120.</p><p>С семикратным произнесением хридая мантры, маслом, молоком и рисом следует разбросать их, разделенных на шесть частей в равных пропорциях между богами, огнем, гуру, учениками, Вардхани и сосудом. Затем следует поднести зубочистку сделанную и кшираврикши ..121-122.</p><p>Место, куда она упадет, (если оно) на западе, севере, северо-востоке и вверху, является (благоприятным). Прочие - неблагоприятны, (для их искупления) должна (быть сделана) восьмисоткартная хома ..123.</p><p>Затем учителю следует выполнить внешний обряд, по всем направления (произнося) мантру ОМ КШАХ КШАХ САРВАБХУТЕБХЙАХ СВАХА ..124.</p><p>Выполнив ачаману, совершив Ньясу и почтив Шанкару (<em>текст поврежден</em>) становится чистым в доме ..125.</p><p>Выполнив Ньясу на ученике и, особенно, на себе, выполнив на рассвете ежедневные обряды следует исследовать сны ..126.</p><p>Благой сон следует растолковать, а на неблагой совершить хому. Если во сне видятся плоды цветы и прочее, женщины, облаченные в прекрасные одежды, преодоление бедствий, нахождение в прекрасном месте, питье вина, отсечение головы, отказ от вкушения мяса, видение божеств, пребывание (с ними) и умащение (божеств), то (садхака) обретет желанные сиддхи ..127-129.</p><p>Подобно этим описываются дурные сны. (Увидев во сне) приготовление мяса и его вкушение, падение в яму и прочее;.130.</p><p>Как сказано в тантрах, совершив недозволенное действие, от которого теряется положение дваждырожденного, мудрому следует совершать почитание богов, огня, гуру и Деви ..131.</p><p>Не следует вкушать ничего не предложенного. Следует избегать имущества Бога, имущества гуру, имущества Деви ..132.</p><p>Знающий мантру не должен беспокоится о том, (является ли она) бесплодной даже один час. Следует быть занятым практикой йоги или практикой мантры ..133.</p><p>Таким образом, дав мантру или выслушав ее, следует выполнить висарджану. Затем (учителю) следует выполнить омовение Бога богов, ученика или себя из сосуда Шивы устраняющего все грехи. Итак, обряд самаи поведан вкратце ..134-135. [small]Такова в священной «Малини виджайоттара тантре» восьмая глава.[/small]</p>',109);a.render=function(m,t,a,l,i,s){return p(),e("div",null,[r])};export default a;export{t as __pageData};
